 {"id":"bd-10i.11.1","title":"Build terminal-model test harness","description":"# Build terminal-model test harness

## Background
Plan Section 0.7 Quality Gate 2 requires: "Property tests validate that applying presenter output to a terminal-model yields the expected grid for supported ops."

The terminal-model is a simplified terminal emulator that we use to verify presenter output correctness WITHOUT needing a real terminal.

## Purpose
A terminal model that:
1. Parses ANSI escape sequences
2. Updates internal grid state
3. Tracks cursor position
4. Tracks style state
5. Enables property testing of presenter output

## Terminal Model Structure

```rust
/// Simplified terminal model for testing presenter output
/// 
/// # Supported Sequences
/// - SGR (Select Graphic Rendition): styles
/// - CUP (Cursor Position): CSI row ; col H
/// - Cursor movement: CSI n A/B/C/D
/// - EL (Erase Line): CSI n K
/// - ED (Erase Display): CSI n J
/// - OSC 8 (Hyperlinks): basic support
/// - DEC synchronized output markers (ignored)
pub struct TerminalModel {
    grid: Vec<Vec<ModelCell>>,
    cursor_x: u16,
    cursor_y: u16,
    current_style: ModelStyle,
    current_link: Option<String>,
    width: u16,
    height: u16,
}

#[derive(Clone, PartialEq, Eq, Debug)]
pub struct ModelCell {
    pub char: char,
    pub style: ModelStyle,
    pub link: Option<String>,
}

#[derive(Clone, PartialEq, Eq, Debug, Default)]
pub struct ModelStyle {
    pub fg: Option<Rgb>,
    pub bg: Option<Rgb>,
    pub bold: bool,
    pub dim: bool,
    pub italic: bool,
    pub underline: bool,
    pub blink: bool,
    pub reverse: bool,
    pub strikethrough: bool,
}

#[derive(Clone, Copy, PartialEq, Eq, Debug)]
pub struct Rgb {
    pub r: u8,
    pub g: u8,
    pub b: u8,
}
```

## ANSI Parser

```rust
impl TerminalModel {
    /// Feed bytes to the terminal model
    pub fn feed(&mut self, bytes: &[u8]) {
        let mut parser = AnsiParser::new();
        for &byte in bytes {
            if let Some(action) = parser.advance(byte) {
                self.execute(action);
            }
        }
    }

    fn execute(&mut self, action: AnsiAction) {
        match action {
            AnsiAction::Print(c) => {
                self.put_char(c);
                self.cursor_x += 1;
                if self.cursor_x >= self.width {
                    self.cursor_x = 0;
                    self.cursor_y = (self.cursor_y + 1).min(self.height - 1);
                }
            }
            AnsiAction::CursorPosition(row, col) => {
                self.cursor_y = row.saturating_sub(1).min(self.height - 1);
                self.cursor_x = col.saturating_sub(1).min(self.width - 1);
            }
            AnsiAction::CursorUp(n) => {
                self.cursor_y = self.cursor_y.saturating_sub(n);
            }
            AnsiAction::CursorDown(n) => {
                self.cursor_y = (self.cursor_y + n).min(self.height - 1);
            }
            AnsiAction::CursorForward(n) => {
                self.cursor_x = (self.cursor_x + n).min(self.width - 1);
            }
            AnsiAction::CursorBack(n) => {
                self.cursor_x = self.cursor_x.saturating_sub(n);
            }
            AnsiAction::EraseLine(mode) => {
                self.erase_line(mode);
            }
            AnsiAction::EraseDisplay(mode) => {
                self.erase_display(mode);
            }
            AnsiAction::Sgr(params) => {
                self.apply_sgr(&params);
            }
            AnsiAction::Osc8Start(url) => {
                self.current_link = Some(url);
            }
            AnsiAction::Osc8End => {
                self.current_link = None;
            }
            AnsiAction::SyncStart | AnsiAction::SyncEnd => {
                // Ignored - just markers
            }
        }
    }

    fn put_char(&mut self, c: char) {
        let x = self.cursor_x as usize;
        let y = self.cursor_y as usize;
        if y < self.grid.len() && x < self.grid[y].len() {
            self.grid[y][x] = ModelCell {
                char: c,
                style: self.current_style.clone(),
                link: self.current_link.clone(),
            };
        }
    }
}
```

## SGR Parsing

```rust
impl TerminalModel {
    fn apply_sgr(&mut self, params: &[u16]) {
        let mut i = 0;
        while i < params.len() {
            match params[i] {
                0 => {
                    self.current_style = ModelStyle::default();
                }
                1 => self.current_style.bold = true,
                2 => self.current_style.dim = true,
                3 => self.current_style.italic = true,
                4 => self.current_style.underline = true,
                5 => self.current_style.blink = true,
                7 => self.current_style.reverse = true,
                9 => self.current_style.strikethrough = true,
                22 => {
                    self.current_style.bold = false;
                    self.current_style.dim = false;
                }
                23 => self.current_style.italic = false,
                24 => self.current_style.underline = false,
                25 => self.current_style.blink = false,
                27 => self.current_style.reverse = false,
                29 => self.current_style.strikethrough = false,
                38 => {
                    // Foreground color
                    if i + 4 < params.len() && params[i + 1] == 2 {
                        self.current_style.fg = Some(Rgb {
                            r: params[i + 2] as u8,
                            g: params[i + 3] as u8,
                            b: params[i + 4] as u8,
                        });
                        i += 4;
                    }
                }
                48 => {
                    // Background color
                    if i + 4 < params.len() && params[i + 1] == 2 {
                        self.current_style.bg = Some(Rgb {
                            r: params[i + 2] as u8,
                            g: params[i + 3] as u8,
                            b: params[i + 4] as u8,
                        });
                        i += 4;
                    }
                }
                _ => {}
            }
            i += 1;
        }
    }
}
```

## Comparison with Buffer

```rust
impl TerminalModel {
    /// Compare terminal model state with an ftui Buffer
    /// Returns list of differences for debugging
    pub fn diff_with_buffer(&self, buffer: &Buffer) -> Vec<CellDiff> {
        let mut diffs = Vec::new();

        for y in 0..self.height.min(buffer.height()) {
            for x in 0..self.width.min(buffer.width()) {
                let model_cell = &self.grid[y as usize][x as usize];
                let buffer_cell = buffer.get(x, y).unwrap();

                if !cells_match(model_cell, buffer_cell) {
                    diffs.push(CellDiff {
                        x, y,
                        model: model_cell.clone(),
                        buffer: describe_cell(buffer_cell),
                    });
                }
            }
        }

        diffs
    }

    /// Assert terminal model matches buffer exactly
    pub fn assert_matches(&self, buffer: &Buffer) {
        let diffs = self.diff_with_buffer(buffer);
        if !diffs.is_empty() {
            panic!("Terminal model does not match buffer:\\n{:#?}", diffs);
        }
    }
}
```

## Property Testing

```rust
use proptest::prelude::*;

proptest! {
    /// Presenter output applied to terminal model produces expected grid
    #[test]
    fn presenter_roundtrip(buffer in arb_buffer(80, 24)) {
        // Start with empty terminal model
        let mut model = TerminalModel::new(80, 24);

        // Present buffer to get ANSI output
        let mut output = Vec::new();
        let mut presenter = Presenter::new(&mut output, caps);
        presenter.present_full(&buffer, &pool, &links)?;

        // Feed output to terminal model
        model.feed(&output);

        // Verify model matches buffer
        model.assert_matches(&buffer);
    }

    /// Diff-based present matches full present
    #[test]
    fn diff_matches_full(
        buffer1 in arb_buffer(80, 24),
        buffer2 in arb_buffer(80, 24)
    ) {
        // Full present of buffer2
        let mut model_full = TerminalModel::new(80, 24);
        let mut output_full = Vec::new();
        Presenter::new(&mut output_full, caps).present_full(&buffer2, ...)?;
        model_full.feed(&output_full);

        // Diff present from buffer1 to buffer2
        let mut model_diff = TerminalModel::new(80, 24);
        model_diff.feed(&present_full_output(&buffer1)); // Start state
        let diff = BufferDiff::compute(&buffer1, &buffer2);
        let mut output_diff = Vec::new();
        Presenter::new(&mut output_diff, caps).present(&buffer2, &diff, ...)?;
        model_diff.feed(&output_diff);

        // Both should produce same final state
        assert_eq!(model_full.grid, model_diff.grid);
    }
}
