## Logging for Test Debugging

```rust
impl TerminalModel {
    /// Dump model state for debugging
    pub fn dump(&self) -> String {
        let mut out = String::new();
        for (y, row) in self.grid.iter().enumerate() {
            out.push_str(&format!("{:3}| ", y));
            for cell in row {
                out.push(cell.char);
            }
            out.push('\\n');
        }
        out.push_str(&format!("Cursor: ({}, {})\\n", self.cursor_x, self.cursor_y));
        out.push_str(&format!("Style: {:?}\\n", self.current_style));
        out
    }
}

#[test]
fn test_with_logging() {
    tracing_test::init();

    let mut model = TerminalModel::new(80, 24);
    tracing::debug!("Initial state:\\n{}", model.dump());

    model.feed(output);
    tracing::debug!("After feed:\\n{}", model.dump());

    let diffs = model.diff_with_buffer(&buffer);
    if !diffs.is_empty() {
        tracing::error!("Differences found: {:#?}", diffs);
    }
}
